"use client";
import { usePathname } from "next/navigation";
import { LiaClipboardListSolid } from "react-icons/lia";
import { MdPendingActions } from "react-icons/md";
import { FaHome } from "react-icons/fa";
import { CgLogOut } from "react-icons/cg";
import { useRouter } from "next/navigation";

export default function AdminLayout({ children }) {
  const pathname = usePathname();
  const router = useRouter();

  return (
    <div className="flex h-screen font-sans">
      {/* Sidebar */}
      <div className="w-60 bg-slate-100 p-5 border-r-2 border-gray-300">
        <h2 className="text-2xl font-bold mb-10">Admin Panel</h2>

        <div className="flex flex-col gap-4"> {/* 🔥 Equal gap between all buttons */}
          <button
            onClick={() => router.push("/admin/pending")}
            className={`w-full py-3 px-4 border-2 flex items-center gap-2 text-left font-semibold ${
              pathname === "/admin/pending"
                ? "bg-black text-white border-black"
                : "bg-white border-black hover:bg-gray-100"
            }`}
          >
            <MdPendingActions className="text-xl" /> Pending Blogs
          </button>

          <button
            onClick={() => router.push("/admin")}
            className={`w-full py-3 px-4 border-2 flex items-center gap-2 text-left font-semibold ${
              pathname === "/admin" || pathname === "/admin/blogs"
                ? "bg-black text-white border-black"
                : "bg-white border-black hover:bg-gray-100"
            }`}
          >
            <LiaClipboardListSolid className="text-xl" /> Blog Lists
          </button>

          <button
            onClick={() => router.push("/")}
            className="w-full py-3 px-4 border-2 border-black bg-white text-black hover:bg-gray-800 hover:text-white flex items-center gap-2 mt-4"
          >
            <FaHome className="text-xl" />
            Go to Homepage
          </button>
          <button
            onClick={() => router.push("/")}
            className="w-full py-3 px-4 border-2 border-black bg-white text-black hover:bg-gray-800 hover:text-white flex items-center gap-2 mt-4"
          >
            <CgLogOut className="text-xl" />
            Log Out
          </button>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 bg-[#fafafa] p-8 overflow-y-auto">{children}</div>
    </div>
  );
}
